// Sync Optimizer untuk 900 Siswa - Batch Processing + Compression
window.SyncOptimizer={_batchSize:50,_batchDelay:1200,_compressionEnabled:!0,_syncStats:{totalRequests:0,successfulSyncs:0,failedSyncs:0,totalDataTransferred:0,startTime:null},initBatchSync:function(e){this._syncStats.startTime=Date.now();const t=Math.ceil(e.length/this._batchSize);console.log(`[SyncOptimizer] Batch sync: ${e.length} items in ${t} batches (${this._batchSize}/batch)`);let i=0;const n=()=>{if(i>=t)return void console.log("[SyncOptimizer] All batches completed");const s=e.slice(i*this._batchSize,(i+1)*this._batchSize);console.log(`[SyncOptimizer] Processing batch ${i+1}/${t} (${s.length} items)`),this._processBatch(s).then(()=>{i++,setTimeout(n,this._batchDelay)}).catch(e=>console.error("[SyncOptimizer] Batch error:",e))};n()},_processBatch:async function(e){const t=e.map(e=>this._syncItem(e));return Promise.allSettled(t)},_syncItem:async function(e){return new Promise((t,i)=>{window.RateLimiter?window.RateLimiter.addToQueue(e.id,async()=>{try{const n=await this._fetchWithCompression(e);this._syncStats.successfulSyncs++,this._syncStats.totalDataTransferred+=n.size||0,t(n)}catch(e){this._syncStats.failedSyncs++,i(e)}}):t(null)})},_fetchWithCompression:async function(e){this._syncStats.totalRequests++;const t=await fetch(`/api/exam/${e.id}`);if(!t.ok)throw new Error(`HTTP ${t.status}`);let i=await t.json();return this._compressionEnabled&&i.questions&&(i.questions=this._compressData(i.questions)),{data:i,size:JSON.stringify(i).length}},_compressData:function(e){if("undefined"==typeof LZ)return e;try{const t=JSON.stringify(e),i=LZ.compress(t);return{_compressed:!0,_data:i}}catch(e){return console.warn("[SyncOptimizer] Compression failed:",e),e}},getStats:function(){const e=Date.now()-this._syncStats.startTime;return{...this._syncStats,elapsedTime:e,avgSpeed:(this._syncStats.totalDataTransferred/e*1e3).toFixed(2)+" KB/s"}},resetStats:function(){this._syncStats={totalRequests:0,successfulSyncs:0,failedSyncs:0,totalDataTransferred:0,startTime:null}}};
